1	export type Cell = [number, number];
2	
3	const isNeighbor = ([x, y]: Cell, [nx, ny]: Cell): boolean =>
4	  Math.max(Math.abs(nx - x), Math.abs(ny - y)) === 1;
5	
6	const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
7	  liveCells.filter((candidate) => isNeighbor(cell, candidate)).length;
8	
9	const survives = (liveNeighbors: number): boolean =>
10	  liveNeighbors === 2 || liveNeighbors === 3;
11	
12	const isLive = (cell: Cell, liveCells: Cell[]): boolean =>
13	  liveCells.some(([x, y]) => x === cell[0] && y === cell[1]);
14	
15	const neighborsOf = ([x, y]: Cell): Cell[] => [
16	  [x - 1, y - 1],
17	  [x, y - 1],
18	  [x + 1, y - 1],
19	  [x - 1, y],
20	  [x + 1, y],
21	  [x - 1, y + 1],
22	  [x, y + 1],
23	  [x + 1, y + 1],
24	];
25	
26	export const nextGeneration = (liveCells: Cell[]): Cell[] => {
27	  const survivors = liveCells.filter((cell) =>
28	    survives(countLiveNeighbors(cell, liveCells)),
29	  );
30	  const births: Cell[] = [];
31	  for (const cell of liveCells) {
32	    for (const neighbor of neighborsOf(cell)) {
33	      if (
34	        !isLive(neighbor, liveCells) &&
35	        !isLive(neighbor, births) &&
36	        countLiveNeighbors(neighbor, liveCells) === 3
37	      ) {
38	        births.push(neighbor);
39	      }
40	    }
41	  }
42	  return [...survivors, ...births];
43	};
